/* ---------- Prompt Box ---------- */

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-prompt-box-container > div:first-child { outline: 1px solid #E1E1E0 !important; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-prompt-box-container > div:first-child { border: 1px solid #FFFFFF !important; }

/* ---------- Input ---------- */

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-text-box { padding-top: 5px; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-text-box textarea { line-height: 1.6em; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-text-box .wixui-text-box__input { padding-top: 15px; }

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-input-switch .wixui-switch__handle { box-shadow: 0 12px 19px -4px var(--shadow-lg-1-color, rgba(0, 0, 0, 0.10)), 0 5px 7px -5px var(--shadow-lg-2-color, rgba(0, 0, 0, 0.10)); }

/* ---------- Plan Tooltip ---------- */

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-plan-tooltip { display: flex; flex-direction: column-reverse; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-plan-tooltip::after { visibility: hidden; opacity: 0; scale: 0.9; width: max-content; max-width: 225px; content: attr(aria-label); font-family: wix-madefor-text-v2, sans-serif; font-size: 12px; color: #232529; text-align: left; position: absolute; margin-bottom: 25px; margin-left: -120px; z-index: 1000000; transform-origin: bottom; background-color: white; padding: 8px 10px; border-radius: 8px; border: 1px solid rgba(15, 15, 15, 0.12); box-shadow: 0 2px 5px 0 rgba(34, 40, 42, 0.08); transition: 0.25s ease-in-out; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-plan-tooltip:hover::after { visibility: visible; opacity: 1; scale: 1.0; transition: 0.25s ease-in-out; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-plan-tooltip:focus::after { visibility: visible; opacity: 1; scale: 1.0; transition: 0.25s ease-in-out; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-plan-tooltip:focus-within::after { visibility: visible; opacity: 1; scale: 1.0; transition: 0.25s ease-in-out; }

/* ---------- Speech Button ---------- */

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-active-speech div:first-child { background: #CCE7E9 !important; animation: scale-loop 1s ease-out infinite; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-active-speech button { background: #E9F4F7; border: 1px solid #7CBFD5; }

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-disabled-speech button__icon { fill: #6E7075 !important; }

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-speech-tooltip { display: flex; flex-direction: column-reverse; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-speech-tooltip::after { visibility: hidden; opacity: 0; scale: 0.9; width: max-content; max-width: 200px; content: attr(aria-label); font-family: wix-madefor-text-v2, sans-serif; font-size: 12px; color: #232529; text-align: left; position: absolute; margin-bottom: 42px; margin-left: -185px; z-index: 1000000; transform-origin: bottom; background-color: white; padding: 8px 10px; border-radius: 8px; border: 1px solid rgba(15, 15, 15, 0.12); box-shadow: 0 2px 5px 0 rgba(34, 40, 42, 0.08); transition: 0.25s ease-in-out; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-speech-tooltip:hover::after { visibility: visible; opacity: 1; scale: 1.0; transition: 0.25s ease-in-out; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-speech-tooltip:focus::after { visibility: visible; opacity: 1; scale: 1.0; transition: 0.25s ease-in-out; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-speech-tooltip:focus-within::after { visibility: visible; opacity: 1; scale: 1.0; transition: 0.25s ease-in-out; }

/* ---------- Switch ---------- */

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-switch__label { opacity: 0; position: absolute; margin: 0; padding: 0; }

/* ---------- Misc ---------- */

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-outline { outline: 1px solid rgba(66, 65, 63, 0.14); border-radius: 14px; }
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-rotation { animation: spin 1s linear infinite; }

/* blur uploaded image to indicate it's loading */
#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-blur-loading-image { filter: blur(5px); }

/* .search-button:hover .button__icon { animation: loop-hover 0.6s linear infinite alternate; } */

/* ---------- Animations ---------- */

@keyframes spin {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
}

@keyframes loop-hover {
  from {
    transform: translateY(2px);
  }
  to {
    transform: translateY(-2px);
  }
}

@keyframes scale-loop {
    from { transform: scale(1.1); }
    50% { transform: scale(1.3); }
    to { transform: scale(1.1); }
}

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-high-z-index{
  z-index: 999;
}

#SITE_CONTAINER #main_MF .css-editing-scope .custom-css-45301db5-b5fd-4c39-9fab-ef83c8f90780 .wixui-dropdown-shadow{
    box-shadow: 0px 5px 10px 0px rgba(15, 15, 15, 0.07);
}
